import type { ReadStream } from 'node:fs'
import { versions } from 'node:process'
import { Readable } from 'node:stream'

// In Node.js versions that do not have the following PR applied, using Readable.toWeb may cause unexpected exceptions.
// https://github.com/nodejs/node/pull/54206
const pr54206Applied = () => {
  const [major, minor] = versions.node.split('.').map((component) => parseInt(component))
  return major >= 23 || (major === 22 && minor >= 7) || (major === 20 && minor >= 18)
}
const useReadableToWeb = pr54206Applied()

export const createStreamBody = (
  stream: ReadStream,
  useNativeReadableToWeb = useReadableToWeb
): ReadableStream<Uint8Array> => {
  if (useNativeReadableToWeb) {
    return Readable.toWeb(stream) as ReadableStream<Uint8Array>
  }

  let controller: ReadableStreamDefaultController<Uint8Array> | undefined
  let settled = false

  const cleanup = () => {
    stream.off('data', onData)
    stream.off('error', onError)
    stream.off('end', onTerminate)
    stream.off('close', onTerminate)
  }

  const settle = (callback?: () => void) => {
    if (settled) {
      return
    }
    settled = true
    cleanup()
    callback?.()
  }

  const onData = (chunk: Buffer | string) => {
    if (settled || !controller) {
      return
    }
    // createReadStream is called without `encoding`, so chunks are always Buffer.
    controller.enqueue(chunk as Buffer)
    if ((controller.desiredSize ?? 0) <= 0) {
      stream.pause()
    }
  }

  const onError = (error: Error) => {
    settle(() => {
      controller?.error(error)
    })
  }

  const onTerminate = () => {
    settle(() => {
      controller?.close()
    })
  }

  return new ReadableStream<Uint8Array>({
    start(streamController) {
      controller = streamController
      stream.on('data', onData)
      stream.on('error', onError)
      stream.on('end', onTerminate)
      stream.on('close', onTerminate)
      stream.pause()
    },

    pull() {
      if (!settled) {
        stream.resume()
      }
    },

    cancel() {
      settle()
      // Suppress late `error` emitted between destroy() and the terminal `close`.
      const ignoreError = () => {}
      stream.on('error', ignoreError)
      stream.once('close', () => stream.off('error', ignoreError))
      stream.destroy()
    },
  })
}

type Range = {
  start: number
  end: number
}

export function findCommentRanges(text: string): Range[] {
  // English comment: lightweight lexer to detect // and /* */ while respecting strings.
  const ranges: Range[] = []
  let i = 0

  let inLine = false
  let inBlock = false
  let inString: "'" | '"' | '`' | null = null
  let escape = false
  let start = 0

  while (i < text.length) {
    const ch = text[i]!
    const next = i + 1 < text.length ? text[i + 1]! : ''

    if (inString) {
      if (escape) {
        escape = false
        i++
        continue
      }
      if (ch === '\\') {
        escape = true
        i++
        continue
      }
      if (ch === inString) {
        inString = null
      }
      i++
      continue
    }

    if (inLine) {
      if (ch === '\n') {
        ranges.push({ start, end: i })
        inLine = false
      }
      i++
      continue
    }

    if (inBlock) {
      if (ch === '*' && next === '/') {
        ranges.push({ start, end: i + 2 })
        inBlock = false
        i += 2
        continue
      }
      i++
      continue
    }

    if (ch === "'" || ch === '"' || ch === '`') {
      inString = ch
      i++
      continue
    }

    if (ch === '/' && next === '/') {
      inLine = true
      start = i
      i += 2
      continue
    }

    if (ch === '/' && next === '*') {
      inBlock = true
      start = i
      i += 2
      continue
    }

    i++
  }

  if (inLine) ranges.push({ start, end: text.length })
  if (inBlock) ranges.push({ start, end: text.length })

  return ranges
}

export function isIndexInRanges(pos: number, ranges: Range[]): boolean {
  for (const r of ranges) {
    if (pos >= r.start && pos < r.end) return true
  }
  return false
}

import { serveStatic } from '@hono/node-server/serve-static';
import { swaggerUI } from '@hono/swagger-ui';
import type { Worker } from 'bullmq';
import { Hono } from 'hono';
import { jwt } from 'hono/jwt';
import env from '../lib/env.js';
import { logger } from '../lib/logger.js';
import { connection } from '../lib/queue.js';
import { UserRepository } from '../repository/user.js';
import { UserService } from '../service/user.js';
import { Tasker } from '../task/tasker.js';
import { AuthController } from './controller/auth.js';
import { serveInternalServerError, serveNotFound } from './controller/resp/error.js';
import { loginValidator, registrationValidator } from './validator/user.js';

export class Server {
  private app: Hono;
  private worker?: Worker;

  constructor(app: Hono) {
    this.app = app;
  }

  public configure() {
    // Index path
    this.app.get('/', (c) => {
      return c.text('Ok');
    });

    // Static files
    this.app.use('/static/*', serveStatic({ root: './' }));

    // API Doc
    this.app.get('/doc', swaggerUI({ url: '/static/openapi.yaml' }));

    // Universal catchall
    this.app.notFound((c) => {
      return serveNotFound(c);
    });

    // Error handling
    this.app.onError((err, c) => {
      return serveInternalServerError(c, err);
    });

    const api = this.app.basePath('/v1');

    // Setup repos
    const userRepo = new UserRepository();

    // Setup services
    const userService = new UserService(userRepo);

    // Setup worker
    this.registerWorker(userService);

    // Setup controllers
    const authController = new AuthController(userService);

    // Register routes
    this.registerUserRoutes(api, authController);
  }

  private registerUserRoutes(api: Hono, authCtrl: AuthController) {
    const user = new Hono();
    const authCheck = jwt({ secret: env.SECRET_KEY });

    user.get('/me', authCheck, authCtrl.me);
    user.post('/login', loginValidator, authCtrl.login);
    user.post('/register', registrationValidator, authCtrl.register);

    api.route('/user', user);
  }

  private registerWorker(userService: UserService) {
    const tasker = new Tasker(userService);
    const worker = tasker.setup();
    if (worker.isRunning()) {
      logger.info('Worker is running');
    }
    this.worker = worker;
  }

  public async shutDownWorker() {
    await this.worker?.close();
    await connection.quit();
  }
}

import { Hono } from "hono";

import { getAllAccounts, getAccount } from "../../db/index";
import { fetchGoodsList } from "../../services/index";
import type { ClientManager } from "../../websocket/client.manager";

export function createGoodsRoutes(
  getClientManager: () => ClientManager | null,
) {
  const router = new Hono();

  // 获取所有账号的商品列表（只获取在线账号）
  router.get("/", async (c) => {
    const accountId = c.req.query("accountId");
    const page = parseInt(c.req.query("page") || "1");

    if (accountId) {
      const account = getAccount(accountId);
      if (!account) {
        return c.json({ error: "Account not found" }, 404);
      }
      const result = await fetchGoodsList(accountId, accountId, page);

      return c.json({
        items: result.items.map((item) => ({ ...item, accountId })),
        nextPage: result.nextPage,
        totalCount: result.totalCount,
      });
    }

    // 获取所有账号，但只处理在线的
    const accounts = getAllAccounts();
    const clientManager = getClientManager();
    const allItems: any[] = [];
    let totalCount = 0;

    for (const account of accounts) {
      // 检查账号是否在线
      const client = clientManager?.getClient(account.id);
      if (!client || !client.isConnected()) {
        continue; // 跳过离线账号
      }

      const result = await fetchGoodsList(account.id, account.id, page);

      const itemsWithAccount = result.items.map((item) => ({
        ...item,
        accountId: account.id,
        accountNickname: account.nickname,
      }));
      allItems.push(...itemsWithAccount);
      totalCount += result.totalCount;
    }

    return c.json({
      items: allItems,
      totalCount,
    });
  });

  // 获取单个账号的商品列表
  router.get("/account/:id", async (c) => {
    const id = c.req.param("id");
    const page = parseInt(c.req.query("page") || "1");

    const account = getAccount(id);
    if (!account) {
      return c.json({ error: "Account not found" }, 404);
    }

    const result = await fetchGoodsList(id, id, page);

    return c.json({
      items: result.items,
      nextPage: result.nextPage,
      totalCount: result.totalCount,
    });
  });

  return router;
}

import { zValidator } from "@hono/zod-validator";
import { type AnyDrizzleDB, buildSchema } from "drizzle-graphql";
import { graphql } from "graphql";
import type { GlobalPlugin } from "honohub";
import { z } from "zod";
import type { GraphQLEditorProps } from "./playground";

export const graphQLBodyValidation = z.object({
  operationName: z.string().optional(),
  query: z.string(),
  variables: z.record(z.string(), z.any()).optional(),
});

export type GraphQLPluginConfig = {
  route?: string;
  playground?:
    | boolean
    | {
        route?: string;
        graphQLEndpoint?: string;
      };
};

const defaultPlaygroundOptions = {
  route: "/playground",
  graphQLEndpoint: "/graphql",
};

export function useGraphQL<Database extends AnyDrizzleDB<any>>(
  options: GraphQLPluginConfig = {},
): GlobalPlugin<Database> {
  const { route = "/graphql" } = options;

  return {
    name: "honohub-graphql",
    bootstrap(props) {
      const { schema } = buildSchema(props.config.db);

      props.app.post(
        route,
        zValidator("json", graphQLBodyValidation),
        async (c) => {
          const data = c.req.valid("json");

          const response = await graphql({
            schema: schema,
            source: data.query,
          });

          return c.json(response);
        },
      );

      return props.app;
    },
    register(config) {
      if (!options.playground) return undefined;

      const { route: playgroundRoute, graphQLEndpoint } = {
        ...defaultPlaygroundOptions,
        ...(typeof options.playground !== "boolean" ? options.playground : {}),
      };

      return {
        ...config,
        routes: [
          ...config.routes,
          {
            icon: "CodeBracketSquareIcon",
            label: "GraphQL Editor",
            path: playgroundRoute,
            import: "@honohub/graphql/playground",
            props(config): GraphQLEditorProps {
              return {
                endpoint: graphQLEndpoint ?? `${config.serverUrl}/graphql`,
              };
            },
          },
        ],
      };
    },
  };
}

import { eq, sql } from "drizzle-orm";
import { HTTPException } from "hono/http-exception";
import db from "../../database";
import { columnTable } from "../../database/schema";
import { VIRTUAL_STATUSES } from "../../task/validate-task-fields";

function toSlug(name: string): string {
  return name
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

async function createColumn({
  projectId,
  name,
  icon,
  color,
  isFinal,
}: {
  projectId: string;
  name: string;
  icon?: string;
  color?: string;
  isFinal?: boolean;
}) {
  const slug = toSlug(name);

  if (!slug) {
    throw new HTTPException(400, {
      message: "Column name must contain at least one alphanumeric character",
    });
  }

  if ((VIRTUAL_STATUSES as readonly string[]).includes(slug)) {
    throw new HTTPException(409, {
      message: `Column slug "${slug}" is reserved for virtual task statuses`,
    });
  }

  const existing = await db
    .select({ id: columnTable.id })
    .from(columnTable)
    .where(
      sql`${columnTable.projectId} = ${projectId} AND ${columnTable.slug} = ${slug}`,
    );

  if (existing.length > 0) {
    throw new HTTPException(409, {
      message: `Column with slug "${slug}" already exists in this project`,
    });
  }

  const [maxPos] = await db
    .select({
      maxPosition: sql<number>`COALESCE(MAX(${columnTable.position}), -1)`,
    })
    .from(columnTable)
    .where(eq(columnTable.projectId, projectId));

  const position = (maxPos?.maxPosition ?? -1) + 1;

  const [created] = await db
    .insert(columnTable)
    .values({
      projectId,
      name,
      slug,
      position,
      icon: icon || null,
      color: color || null,
      isFinal: isFinal ?? false,
    })
    .returning();

  if (!created) {
    throw new HTTPException(500, { message: "Failed to create column" });
  }

  return created;
}

export default createColumn;

import { eq } from "drizzle-orm";
import { HTTPException } from "hono/http-exception";
import db from "../../database";
import { labelTable, projectTable, taskTable } from "../../database/schema";
import { publishEvent } from "../../events";
import {
  removeLabelFromGitea,
  syncLabelToGitea,
} from "../../plugins/gitea/utils/sync-label-to-gitea";
import {
  removeLabelFromGitHub,
  syncLabelToGitHub,
} from "../../plugins/github/utils/sync-label-to-github";

async function assignLabelToTask(id: string, taskId: string, userId: string) {
  const label = await db.query.labelTable.findFirst({
    where: (label, { eq }) => eq(label.id, id),
  });

  if (!label) {
    throw new HTTPException(404, {
      message: "Label not found",
    });
  }

  const [task] = await db
    .select({
      id: taskTable.id,
      projectId: taskTable.projectId,
      workspaceId: projectTable.workspaceId,
    })
    .from(taskTable)
    .innerJoin(projectTable, eq(taskTable.projectId, projectTable.id))
    .where(eq(taskTable.id, taskId))
    .limit(1);

  if (!task) {
    throw new HTTPException(404, {
      message: "Task not found",
    });
  }

  if (label.workspaceId && label.workspaceId !== task.workspaceId) {
    throw new HTTPException(400, {
      message: "Label and task must belong to the same workspace",
    });
  }

  const [updatedLabel] = await db
    .update(labelTable)
    .set({ taskId })
    .where(eq(labelTable.id, id))
    .returning();

  if (!updatedLabel) {
    throw new HTTPException(500, {
      message: "Failed to attach label to task",
    });
  }

  if (label.taskId && label.taskId !== taskId) {
    removeLabelFromGitHub(label.taskId, label.name).catch((error) => {
      console.error("Failed to remove label from GitHub:", error);
    });
    removeLabelFromGitea(label.taskId, label.name).catch((error) => {
      console.error("Failed to remove label from Gitea:", error);
    });
  }

  syncLabelToGitHub(taskId, updatedLabel.name, updatedLabel.color).catch(
    (error) => {
      console.error("Failed to sync label to GitHub:", error);
    },
  );
  syncLabelToGitea(taskId, updatedLabel.name, updatedLabel.color).catch(
    (error) => {
      console.error("Failed to sync label to Gitea:", error);
    },
  );

  await publishEvent("task.label_assigned", {
    label: updatedLabel,
    task,
    projectId: task.projectId,
    taskId: task.id,
    userId,
    type: "label_assigned",
  });

  return updatedLabel;
}

export default assignLabelToTask;

import { createHash, randomUUID } from "node:crypto";
import { createId } from "@paralleldrive/cuid2";
import db from "../database";
import { sessionTable } from "../database/schema";

type RegisteredClient = {
  clientId: string;
  redirectUris: string[];
  clientName?: string;
  issuedAt: number;
};

type AuthCode = {
  clientId: string;
  userId: string;
  codeChallenge: string;
  redirectUri: string;
  expiresAt: number;
};

const clients = new Map<string, RegisteredClient>();
const codes = new Map<string, AuthCode>();

export function getClient(clientId: string): RegisteredClient | undefined {
  return clients.get(clientId);
}

export function registerClient(params: {
  redirectUris: string[];
  clientName?: string;
}): RegisteredClient {
  const clientId = randomUUID();
  const client: RegisteredClient = {
    clientId,
    redirectUris: params.redirectUris,
    clientName: params.clientName,
    issuedAt: Math.floor(Date.now() / 1000),
  };
  clients.set(clientId, client);
  return client;
}

export function createAuthCode(params: {
  clientId: string;
  userId: string;
  codeChallenge: string;
  redirectUri: string;
}): string {
  const code = randomUUID();
  codes.set(code, {
    ...params,
    expiresAt: Date.now() + 5 * 60 * 1000,
  });
  return code;
}

function base64url(buf: Buffer): string {
  return buf.toString("base64url");
}

function verifyPkce(codeVerifier: string, codeChallenge: string): boolean {
  const hash = createHash("sha256").update(codeVerifier).digest();
  return base64url(hash) === codeChallenge;
}

export async function exchangeCode(
  code: string,
  clientId: string,
  codeVerifier: string,
  redirectUri: string,
): Promise<{ accessToken: string; expiresIn: number } | null> {
  const stored = codes.get(code);
  if (!stored) return null;
  codes.delete(code);

  if (stored.clientId !== clientId) return null;
  if (stored.redirectUri !== redirectUri) return null;
  if (stored.expiresAt < Date.now()) return null;
  if (!verifyPkce(codeVerifier, stored.codeChallenge)) return null;

  const sessionToken = randomUUID();
  const expiresIn = 30 * 24 * 60 * 60;

  await db.insert(sessionTable).values({
    id: createId(),
    token: sessionToken,
    userId: stored.userId,
    expiresAt: new Date(Date.now() + expiresIn * 1000),
    createdAt: new Date(),
    updatedAt: new Date(),
  });

  return { accessToken: sessionToken, expiresIn };
}

